import React, { useEffect, useState } from 'react';

function App() {
  const [campaigns, setCampaigns] = useState([]);
  const [filters, setFilters] = useState({ id: '', name: '', status: '' });

  const fetchCampaigns = () => {
    const params = new URLSearchParams();
    if (filters.id) params.append('id', filters.id);
    if (filters.name) params.append('name', filters.name);
    if (filters.status) params.append('status', filters.status);

    const qs = params.toString();
    const url = '/api/campaigns' + (qs ? `?${qs}` : '');
    console.log('fetching', url);
    fetch(url)
      .then(res => res.json())
      .then(data => {
        if (data.success) setCampaigns(data.data);
      })
      .catch(console.error);
  };

  useEffect(() => {
    fetchCampaigns();
  }, [filters]);

  const handleChange = e => {
    const { name, value } = e.target;
    setFilters(f => ({ ...f, [name]: value }));
  };

  const clearFilters = () => setFilters({ id: '', name: '', status: '' });

  const editCampaign = async campaign => {
    const newStatus = window.prompt(
      'New status (1=Active, 0=Paused):',
      campaign.status
    );
    if (newStatus === null) return; 
    if (!['0', '1', 0, 1].includes(newStatus)) {
      alert('Status must be 0 or 1');
      return;
    }

    const newLanding = window.prompt(
      'Landing URL:',
      campaign.landingUrl
    );
    if (newLanding === null) return;

    const body = { id: campaign.id, status: newStatus, landingUrl: newLanding };
    try {
      const res = await fetch(`/api/campaigns/${campaign.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body)
      });
      const data = await res.json();
      if (res.ok) {
        alert('Campaign updated');
        fetchCampaigns();
      } else {
        alert('Error: ' + (data.error || data.message));
      }
    } catch (err) {
      console.error(err);
      alert('Network error');
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <h1>Campaigns</h1>
      <div style={{ marginBottom: 20 }}>
        <label>
          ID:{' '}
          <input
            name="id"
            value={filters.id}
            onChange={handleChange}
            placeholder="search by id"
          />
        </label>{' '}
        <label>
          Name:{' '}
          <input
            name="name"
            value={filters.name}
            onChange={handleChange}
            placeholder="search by contained text in name"
          />
        </label>{' '}
        <label>
          Status:{' '}
          <select name="status" value={filters.status} onChange={handleChange}>
            <option value="">Any</option>
            <option value="1">Active</option>
            <option value="0">Paused</option>
          </select>
        </label>{' '}
        <button onClick={clearFilters}>Clear</button>
      </div>
      <ul style={{ listStyle: 'none', padding: 0 }}>
        {campaigns.map(c => (
          <li
            key={c.id}
            style={{
              display: 'flex',
              alignItems: 'center',
              marginBottom: 16,
              padding: 12,
              border: '1px solid #ccc',
              borderRadius: 4
            }}
          >
            <img
              src={c.imageUrl}
              alt={c.name}
              style={{
                width: 80,
                height: 80,
                objectFit: 'cover',
                marginRight: 16
              }}
            />
            <div style={{ flex: 1 }}>
              <div style={{ fontWeight: 'bold' }}>{c.name}</div>
              <div>
                <a
                  href={c.landingUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                >
                  {c.landingUrl}
                </a>
              </div>
            </div>
            <div style={{ marginLeft: 16 }}>
              {c.status === '1' ? 'Active' : 'Paused'}
            </div>
            <button
              onClick={() => editCampaign(c)}
              style={{
                marginLeft: 16,
                cursor: 'pointer',
                background: 'none',
                border: 'none',
                fontSize: 18
              }}
              title="Edit campaign"
            >
              ✏️
            </button>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default App;
